SELECT ?actorLabel WHERE {
  ?film wdt:P31 wd:Q11424 ;
        wdt:P1476 "Constantine"@en .
  ?film p:P161 ?castStatement .
  ?castStatement ps:P161 ?actor .
  ?actor rdfs:label ?actorLabel .
  ?actor wdt:P21 wd:Q6581097 .  
  FILTER (?actorLabel != "Rachel Weisz"@en)
  LIMIT 1
}

